import React, { 
    // useState, 
    // useEffect 
} from 'react'
import Wave from "./Wave";
import {Link} from 'react-router-dom';

export default function Intro({email, resume, name}) {
    return (
        <section className="intro">
            <h1 className="intro__hello">Hello!
                <Wave />
            </h1>
            <h2 className="intro__tagline">I'm 
                <span className="name"> {name ? name : "Sanjay Goraniya"}</span>,<br />
                I build things for the web.<span className="emoji technologist"></span><br />
                <span className="specialty">Back-End &amp; Front-End Developer / AWS Expert</span>
            </h2>
            <div className="intro__contact">
                <a href={email} target="_blank" className="email-link" rel="noreferrer">
                    Get In Touch
                </a>
                <Link to={resume} className="email-link" rel="noreferrer">
                    Get Resume
                </Link>
            </div>
        </section>
    )
}
