import React, {useEffect} from 'react';
import {Link} from 'react-router-dom';

const NotFound = () => {
    useEffect(() => {
        document.body.classList.add("not-found");
        return () => {
            document.body.classList.remove("not-found");
        }
    });
    return (
        <section className="not-found-content">
            <div className="name">Sanjay Goraniya</div>
            <div>
                <h1>404</h1>
                <h4>Looks like you're looking for a page that doesn't exist.</h4>
            </div>
            <Link to="/" className="email-link" rel="noreferrer">
                Home Page
            </Link>
        </section>
    )

}
export default NotFound;