import React, { useState, useEffect } from 'react'

export default function Switch() {
    const [checked, setChecked] = useState(false);


    useEffect(() => {
        // Night between 7pm and 7am
        let hours = new Date().getHours();
        if (hours >= 19 || hours <= 7) {
            document.body.classList.add("dark");
            setChecked(true);
        }
    }, []);

    useEffect(() => {
        document.body.classList.toggle("dark", checked);
        let manifest = document.querySelector("#manifest")
        if(checked) {
            manifest.href='/manifest-dark.json';            
        } else {
            manifest.href='/manifest-light.json';
        }
        return () => {
            
        }
    }, [checked]);

    // Handle theme button click
    const handleChange = (e) => setChecked(e.target.checked);

    return (
        <div className="toggle-theme-wrapper">
            <input id="toggle-switch" type="checkbox" checked={checked} onChange={handleChange} />
            <label htmlFor="toggle-switch">
                <svg className="sun" height={22} width={22} xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" fill="none" stroke="#FDB813" strokeWidth={2} strokeLinecap="round" strokeLinejoin="round">
                    <circle cx={12} cy={12} r={5} fill="none" />
                    <line x1={12} y1={1} x2={12} y2={3} />
                    <line x1={12} y1={21} x2={12} y2={23} />
                    <line x1="4.22" y1="4.22" x2="5.64" y2="5.64" />
                    <line x1="18.36" y1="18.36" x2="19.78" y2="19.78" />
                    <line x1={1} y1={12} x2={3} y2={12} />
                    <line x1={21} y1={12} x2={23} y2={12} />
                    <line x1="4.22" y1="19.78" x2="5.64" y2="18.36" />
                    <line x1="18.36" y1="5.64" x2="19.78" y2="4.22" />
                </svg>
                <svg className="moon" height={26} width={26} xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth={2} strokeLinecap="round" strokeLinejoin="round">
                    <path d="M21 12.79A9 9 0 1 1 11.21 3 7 7 0 0 0 21 12.79z" fill="none" />
                </svg>
            </label>
        </div>
    )
}
