import React from 'react'
// import PropTypes from 'prop-types'
import { Switch, Footer, TopButton } from './index';

const Layout = ({children, social}) => {
    return (
        <>
            <Switch />
            {children ? children : null}
            <Footer social={social} />
            <TopButton />
        </>
    )
}

// Layout.propTypes = {

